INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cd7c078d-c772-426f-bedd-6a1ba777829d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Component Design — Single Responsibility, the 150-Line Rule, and Separating Logic from JSX$escape$,
  $escape$Qwik's optimizer serializes component boundaries into QRLs — the more logic packed into one `component$()`, the coarser the lazy-loading granularity. Single responsibility isn't just clean code here; it's a performance contract.

The 150-line rule has real teeth in Qwik: a bloated `component$()` forces the optimizer to bundle a larger resumable chunk. Split logic from presentation by extracting custom hooks — named `use*` functions that compose `useSignal()`, `useTask$()`, and `useComputed$()` — and keep `component$()` responsible only for returning JSX.

This separation also sharpens Qwik's fine-grained reactivity. When a `useSignal()` lives inside a dedicated hook, only subscribers to that signal re-render on change. Mixing data-fetching, transformation, and rendering in one `component$()` creates unnecessary subscription coupling across the tree.

`useVisibleTask$()` especially should never cohabit with layout markup. Extract client-only effects into a dedicated hook, leaving the `component$()` body a thin JSX shell. The optimizer can then tree-shake and defer each unit independently — the payoff Qwik's architecture is built around.$escape$,
  $escape$// useProductData.ts — logic only
export const useProductData = (id: string) => {
  const product = useSignal<Product | null>(null);
  const error = useSignal<string | null>(null);

  useTask$(async ({ track }) => {
    track(() => id);
    try {
      product.value = await fetchProduct(id);
    } catch (e) {
      error.value = 'Failed to load';
    }
  });

  return { product, error };
};

// ProductCard.tsx — presentation only
export const ProductCard = component$<{ id: string }>(({ id }) => {
  const { product, error } = useProductData(id);
  if (error.value) return <p>{error.value}</p>;
  return <div class="card">{product.value?.name ?? 'Loading…'}</div>;
});$escape$,
