INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6540d160-73ce-4e59-8c05-5713ac0cff83',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik State Management — Local Signal, Lifted Prop, Context Store, or External?$escape$,
  $escape$Qwik's reactivity is signal-based, so state placement rules differ from VDOM frameworks. `useSignal<T>()` gives a primitive reactive value; `useStore<T>()` gives a deep-reactive object proxy — both scope to the current component and serialize into its QRL boundary on SSR.

Lifting in Qwik is uniquely zero-cost: pass the signal ref itself as a prop. The child subscribes directly to the signal — the parent component does not re-execute. No cascading renders, unlike React's lifted state.

For sub-tree sharing, use `createContextId<T>()` + `useContextProvider()` in the ancestor and `useContext()` in consumers. Qwik's context stores are resumable — serialized in the SSR payload, individual components resume only when they interact with that slice.

External stores (Nanostores, module-level `useStore()`) suit cross-route or singleton state. Caution: module-level stores live outside Qwik's serialization boundary and break resumability — they must be re-initialized on the client. For anything SSR-sensitive, always prefer context.

Decision ladder: `useSignal` (local atom) → lifted signal prop (sibling coordination) → context store (sub-tree) → external store (app-wide or cross-route).$escape$,
  $escape$import { component$, createContextId, useContext, useContextProvider, useSignal, useStore, type Signal } from '@builder.io/qwik';

const UserCtx = createContextId<{ name: string }>('user');

export const Root = component$(() => {
  const user = useStore({ name: 'Ada' });    // context store — shared sub-tree
  useContextProvider(UserCtx, user);
  const count = useSignal(0);                // local signal — only Root reads it
  return <Child count={count} />;           // lift signal ref as prop
});

export const Child = component$<{ count: Signal<number> }>(({ count }) => {
  const user = useContext(UserCtx);          // context consumer, no prop drilling
  return <button onClick$={() => count.value++}>{user.name}: {count.value}</button>;
});$escape$,
