INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '876358fc-53fa-4e2e-8424-ef72400ad642',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Data Fetching — Server State vs Client State and Where TanStack Query Fits$escape$,
  $escape$Qwik separates data fetching at the architecture level, not just the API level. `routeLoader$` runs exclusively on the server — its result is serialized into HTML and resumed on the client via Qwik's resumability model. No re-execution, no client waterfall. This is your server state primitive.

For reactive client state, `useResource$` is the idiomatic answer. It accepts a `track` callback to declare signal dependencies — when tracked signals change, the resource re-runs automatically. The `cleanup` callback handles request cancellation via AbortController, solving the stale-request problem that TanStack Query handles with `queryKey` invalidation.

Where TanStack Query gives you a global `queryClient` with `staleTime` and cache invalidation, Qwik's `routeLoader$` cache is per-request and tied to the routing layer. Mutations flow through `routeAction$`, which triggers automatic `routeLoader$` revalidation on the current route — no manual `invalidateQueries` needed.

Reach for `routeLoader$` for any data needed at page load. Use `useResource$` for user-driven, signal-dependent fetches like search or filters. Only introduce TanStack Query when you need cross-route cache sharing or background refetch strategies — Qwik's built-ins cover the vast majority of real-world cases without the extra dependency.$escape$,
  $escape$import { component$, useSignal } from '@builder.io/qwik';
import { routeLoader$, useResource$, Resource } from '@builder.io/qwik-city';

// Server state: serialized at SSR, never re-runs on client
export const useUser = routeLoader$(async ({ params }) => {
  return fetchUser(params.id);
});

export default component$(() => {
  const user = useUser(); // already resolved — zero client waterfall

  const query = useSignal('');
  const results = useResource$(async ({ track, cleanup }) => {
    track(() => query.value);          // re-fetch when query changes
    const ctrl = new AbortController();
    cleanup(() => ctrl.abort());       // cancel stale requests
    return search(query.value, { signal: ctrl.signal });
  });

  return (
    <>
      <p>User: {user.value.name}</p>
      <input bind:value={query} />
      <Resource value={results} onResolved={(r) => <Results data={r} />} />
    </>
  );
});$escape$,
