INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '360cac82-7b4a-4e2e-be92-c6ee1674a434',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Error Boundaries — Per-Route Isolation with Resource State Handling$escape$,
  $escape$Qwik City's file-based router lets you colocate error boundaries by dropping an `error.tsx` inside any route segment — it catches unhandled throws from `routeLoader$` and `routeAction$` scoped to that subtree, leaving sibling routes unaffected.

For async data inside components, `useResource$` paired with the `<Resource>` component gives you first-class loading, error, and empty states without extra flags. The `<Resource>` JSX primitive accepts three render props: `onPending` streams a skeleton while the server serializes the resource, `onRejected` receives the thrown Error object, and `onResolved` receives the resolved value. Crucially, these states are tracked at the signal level — only the affected DOM subtree re-renders on transition, not the whole route.

If a `routeLoader$` throws inside a layout, the nearest `error.tsx` boundary catches it; if none exists in the layout chain, Qwik City falls back to the root `src/routes/error.tsx`. For expected empty states (zero results), check inside `onResolved` rather than treating them as errors — throwing for empty data pollutes your error telemetry and bypasses the normal render path.$escape$,
  $escape$// src/routes/feed/index.tsx
import { component$, useResource$, Resource } from '@builder.io/qwik';
import { routeLoader$ } from '@builder.io/qwik-city';

export const usePosts = routeLoader$(async ({ fail }) => {
  const res = await fetch('https://api.example.com/posts');
  if (!res.ok) throw fail(res.status, { message: 'Feed unavailable' });
  return res.json() as Promise<Post[]>;
});

export default component$(() => {
  const postsSignal = usePosts();
  return (
    <Resource
      value={postsSignal}
      onPending={() => <p>Loading feed…</p>}
      onRejected={(err) => <p class="text-red-500">{err.message}</p>}
      onResolved={(posts) =>
        posts.length === 0
          ? <p>No posts yet.</p>
          : <ul>{posts.map(p => <li key={p.id}>{p.title}</li>)}</ul>
      }
    />
  );
});

// src/routes/feed/error.tsx  — scoped boundary for this route only
export default component$(() => <h2>Feed failed to load. Try again.</h2>);$escape$,
  $escape$typescript$escape$,
