INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4117df45-aa6c-4ed6-989f-dd70bcaf7bf3',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Testing — Test What Users See, Not What Signals Hold$escape$,
  $escape$Qwik's lazy execution model makes testing implementation details especially risky — signals serialize across resumability boundaries, meaning what a signal holds during a test may differ from what it holds after browser resumption. The fix: test rendered output, not internal state.

`createDOM()` from `@builder.io/qwik/testing` gives you a headless DOM with `render`, `screen`, and `userEvent`. Resist the urge to read `signal.value` in assertions. Query the DOM and assert on text content, ARIA attributes, or element presence — exactly what a user observes.

This matters for `$`-suffixed handlers too. Qwik serializes `onClick$` closures into QRL chunks; the handler will not be the same function reference across resumption. Asserting `onClick$ === fn` will always fail. Assert on the side effect: the DOM mutation.

The same rule applies to stores and computed signals. Prefer `screen.querySelector('[aria-label="count"]')!.textContent` over `store.count`. Behaviour is durable across serialization; internal shape is not.$escape$,
  $escape$import { createDOM } from '@builder.io/qwik/testing';
import { component$, useSignal } from '@builder.io/qwik';

const Counter = component$(() => {
  const count = useSignal(0);
  return <button onClick$={() => count.value++}>Count: {count.value}</button>;
});

test('shows updated count after click', async () => {
  const { screen, render, userEvent } = await createDOM();
  await render(<Counter />);

  expect(screen.querySelector('button')!.textContent).toBe('Count: 0');
  await userEvent('button', 'click');
  expect(screen.querySelector('button')!.textContent).toBe('Count: 1');
  // Never accessed count.value — tested rendered output only
});$escape$,
  $escape$typescript$escape$,
