INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f7e7dae6-e458-4329-8c3d-dc6180b3f9ae',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Security — dangerouslySetInnerHTML, Token Storage, and Input Sanitization$escape$,
  $escape$Qwik's dangerouslySetInnerHTML bypasses the framework's default escaping — user-generated HTML rendered this way is a direct XSS vector. Always sanitize with `isomorphic-dompurify` before passing content to it; DOMPurify runs safely in both server-side (Node) and browser contexts where Qwik resumes.

For token storage, never use `localStorage` or `sessionStorage` — they're readable by any injected script. Qwik City's `routeAction$` and `routeLoader$` run server-side and expose `RequestEventBase`, where `cookie.set()` lets you issue HttpOnly, Secure, SameSite=Lax cookies. These tokens are entirely invisible to client JavaScript, making them safe across Qwik's resumability boundary.

Input sanitization belongs in `routeAction$` using `zod$` — this binds the schema directly to the action at the type level, rejecting malformed payloads before they reach business logic. Because Qwik's resumability means `server$` functions can re-execute on navigation, treat every server entry point as untrusted. Validate at each boundary, not just on initial page load.$escape$,
  $escape$import { component$ } from '@builder.io/qwik';
import { routeAction$, zod$, z } from '@builder.io/qwik-city';
import DOMPurify from 'isomorphic-dompurify';

// Tokens in HttpOnly cookies — never localStorage
export const useLoginAction = routeAction$(
  async (data, { cookie }) => {
    const token = await authenticate(data.email, data.password);
    cookie.set('auth_token', token, {
      httpOnly: true, secure: true, sameSite: 'Lax', path: '/'
    });
  },
  zod$({ email: z.string().email(), password: z.string().min(8) })
);

// Sanitize user HTML before dangerouslySetInnerHTML
export const SafeHtml = component$<{ html: string }>(({ html }) => {
  const clean = DOMPurify.sanitize(html, { ALLOWED_TAGS: ['b', 'i', 'em', 'code'] });
  return <div dangerouslySetInnerHTML={clean} />;
});$escape$,
  $escape$typescript$escape$,
