INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '149e00e1-d569-45cc-8351-4d9f73300593',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Code Quality — ESLint Plugin, $ Naming Contracts, and the 50-Line Rule$escape$,
  $escape$Qwik's optimizer is pattern-driven: it identifies resumable boundaries by the `$` suffix. Use the wrong name and the optimizer silently skips the extraction — no build error, just a broken bundle. The React `eslint-plugin-react-hooks` doesn't apply here; Qwik has its own: `eslint-plugin-qwik`. It enforces the `$` naming contract (flagging misnamed lazy functions), warns when `useTask$` or `useVisibleTask$` are called outside a `component$`, and catches inline arrow functions passed to `onClick$` that aren't wrapped in `$()`. Install via `pnpm add -D eslint-plugin-qwik` and extend `plugin:qwik/recommended`.

For naming: every function crossing a resumption boundary must end in `$`. Custom hook conventions follow the same rule — `useCounter$`, not `useCounter`. For the 50-line limit, scope it to `component$` bodies using `max-lines-per-function`. A bloated `component$` expands the serialized QRL closure, increasing the resumption payload on the client. Extract heavy logic into standalone `$`-wrapped helpers or split into child `component$` exports — each becomes its own lazy chunk.$escape$,
  $escape$// eslint.config.mjs
import qwikPlugin from 'eslint-plugin-qwik';

export default [
  {
    plugins: { qwik: qwikPlugin },
    rules: {
      ...qwikPlugin.configs.recommended.rules,
      // Scoped to component$ / useTask$ bodies, not entire files
      'max-lines-per-function': ['warn', { max: 50, skipBlankLines: true, skipComments: true }],
      // Catch $ suffix violations the plugin misses
      'id-match': ['error', '^(use[A-Z].*\\$|[a-z].*\\$|[A-Z].*)$', { onlyDeclarations: false }],
    },
  },
];$escape$,
  $escape$javascript$escape$,
