INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f154dd91-13a3-4d82-b9de-614708a9b9ec',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Accessibility — Semantic HTML First, useVisibleTask$ for Focus, ARIA as a Last Resort$escape$,
  $escape$Qwik's resumability model changes how you think about accessibility. Since components resume rather than hydrate, focus management tied to useEffect patterns from other frameworks doesn't apply — use useVisibleTask$ instead, which runs exclusively in the browser after the component is visible in the DOM.

Start with semantic HTML: <button> over <div onClick$>, <nav> over <div role='navigation'>, <dialog> over a custom overlay div. These carry implicit ARIA roles, keyboard semantics, and browser-native behavior for free.

When HTML falls short — a custom combobox, a focus trap inside a modal — use useVisibleTask$ with track() to respond to signal changes and imperatively manage focus. Avoid useTask$ for DOM focus: it runs in both SSR and browser contexts, so element.focus() will throw server-side.

Add ARIA only at the boundary. aria-modal='true' on <dialog> aids screen readers in certain agents. aria-expanded on a custom trigger should be bound directly to the signal driving it — Qwik's fine-grained reactivity keeps the attribute in sync automatically without manual bookkeeping. Never add role='button' to a div when a real <button> works.$escape$,
  $escape$import { component$, useSignal, useVisibleTask$ } from '@builder.io/qwik';

export const ConfirmDialog = component$<{ open: boolean }>(({ open }) => {
  const dialogRef = useSignal<HTMLDialogElement>();

  useVisibleTask$(({ track }) => {
    track(() => open);
    const el = dialogRef.value;
    if (open && el) el.focus();
  });

  return (
    <dialog ref={dialogRef} aria-modal="true" open={open}>
      <h2>Confirm</h2>
      <button onClick$={() => dialogRef.value?.close()}>OK</button>
    </dialog>
  );
});$escape$,
  $escape$typescript$escape$,
