INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '62d50475-6cd9-4721-8ccb-99ede2d9ef63',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Web Vitals — How Resumability and Component Patterns Shape LCP, CLS, and INP$escape$,
  $escape$Qwik's resumability means no hydration replay on load — the DOM is already interactive without re-executing component trees. But your component patterns still directly determine Core Web Vitals scores.

**LCP:** `useVisibleTask$` with `strategy: 'document-ready'` runs JS eagerly, competing with paint. The default `strategy: 'intersection-observer'` defers execution until the element is visible — always prefer it for non-critical widgets. For hero content, stream it via `routeLoader$` so the LCP element lands in SSR HTML with zero JS dependency.

**CLS:** Qwik skips client-side re-rendering of SSR'd nodes, eliminating hydration-induced DOM mutations entirely. The remaining risk is signal-driven renders: if a `useSignal` update changes layout dimensions before the value resolves, reserve space upfront with CSS `min-height` or `aspect-ratio`.

**INP:** `$`-suffixed handlers (e.g., `onClick$`) are QRL lazy-loaded on first interaction, keeping the main thread idle during load. The trap is synchronous heavy work inside those handlers — it still blocks the frame. Offload expensive logic to `useTask$` with `track` dependencies, or wrap in a QRL-isolated function so Qwik can code-split it independently.$escape$,
  $escape$import { component$, useSignal, useVisibleTask$ } from '@builder.io/qwik';
import { routeLoader$ } from '@builder.io/qwik-city';

// routeLoader$ → SSR'd content, LCP element has zero JS dependency
export const useArticles = routeLoader$(async () =>
  fetch('/api/articles').then(r => r.json())
);

export const Feed = component$(() => {
  const articles = useArticles();       // SSR-rendered, LCP-safe
  const open = useSignal(false);        // surgical signal update, no tree re-render

  useVisibleTask$(async () => {
    // strategy: 'intersection-observer' (default) — deferred until visible
    await import('./analytics').then(m => m.track('feed-view'));
  });

  return (
    <section style={{ minHeight: '480px' }}>  {/* reserve space → no CLS */}
      {articles.value.map(a => <article key={a.id}>{a.title}</article>)}
      {/* onClick$ is lazy-loaded on first click → low INP, no upfront JS cost */}
      <button onClick$={() => (open.value = !open.value)}>More</button>
    </section>
  );
});$escape$,
  $escape$typescript$escape$,
