INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '307de096-711a-4ab1-a68f-f68857741b5e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Memory Leaks — Cleanup with useVisibleTask$, AbortController, and removeEventListener$escape$,
  $escape$Qwik's `useVisibleTask$` runs exclusively in the browser after a component becomes visible — but without explicit cleanup, subscriptions and fetches outlive the component. Unlike React's `useEffect`, Qwik does not use a return value for teardown. Instead, the `{ cleanup }` destructured argument accepts a callback that fires when the task re-runs or the component is destroyed.

For event listeners, always pair `addEventListener` with `removeEventListener` inside `cleanup`. For async operations, `AbortController` is your cancellation primitive: pass `signal` to `fetch` and call `controller.abort()` in the cleanup. Qwik's resumability means a component can be hydrated, paused, and re-hydrated — leaked listeners accumulate across these transitions in ways React developers don't anticipate.

`useTask$` (server + client) also accepts `{ cleanup }`, useful for tearing down interval timers or reactive subscriptions. However, `useTask$` has no DOM access on the server — wrap any `window` or `document` references in an `isServer` guard or move them into `useVisibleTask$` entirely.

Treating cleanup as a first-class concern prevents ghost listeners and aborted-request noise from polluting your DevTools network tab.$escape$,
  $escape$import { component$, useVisibleTask$ } from '@builder.io/qwik';

export default component$(() => {
  useVisibleTask$(({ cleanup }) => {
    const controller = new AbortController();
    const handler = (e: Event) => console.log('scrolled', e);

    window.addEventListener('scroll', handler);
    fetch('/api/feed', { signal: controller.signal });

    cleanup(() => {
      window.removeEventListener('scroll', handler);
      controller.abort();
    });
  });

  return <div>Feed</div>;
});$escape$,
