INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '515c55e1-ea37-4827-acc4-e7757352d50a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik WebSockets — Singleton Connections, Reconnection Logic, and Optimistic UI$escape$,
  $escape$Qwik's resumability means `useVisibleTask$` is your entry point for WebSockets — it runs client-side only, after the component is visible, without blocking SSR. For a singleton, define the socket at module scope: a `getWS()` helper checks `readyState` (0 = CONNECTING, 1 = OPEN) before creating a new instance, giving you free reconnection guarding.

Inside `useVisibleTask$`, attach `onmessage` to push into a `useSignal<string[]>`, and register `cleanup(() => socket.close())` — this only fires on unmount, not on re-renders, so you won't thrash the connection. Qwik's fine-grained reactivity re-renders only the DOM nodes subscribed to that signal, not the whole component.

For optimistic UI, append to `messages.value` before calling `socket.send()`. On an `onerror` or server-sent rejection event, splice the speculative entry out. Because signals are serialized into HTML during SSR, your initial message list can be server-rendered — the WebSocket then hydrates into that state with zero loading flicker.

Reconnection backoff lives in `socket.onclose`: schedule `setTimeout(() => reconnect(url), Math.min(30000, delay * 2))` and re-attach all handlers in the callback.$escape$,
  $escape$// ws.ts
let ws: WebSocket | null = null;
export const getWS = (url: string) => {
  if (!ws || ws.readyState > 1) ws = new WebSocket(url);
  return ws;
};

// ChatComponent.tsx
export default component$(() => {
  const messages = useSignal<string[]>([]);
  const draft = useSignal('');

  useVisibleTask$(({ cleanup }) => {
    const socket = getWS('wss://api.example.com/ws');
    socket.onmessage = (e) => (messages.value = [...messages.value, e.data]);
    cleanup(() => socket.close());
  });

  const send = $(() => {
    messages.value = [...messages.value, draft.value]; // optimistic
    getWS('wss://api.example.com/ws').send(JSON.stringify({ text: draft.value }));
    draft.value = '';
  });

  return <button onClick$={send}>Send</button>;
});$escape$,
  $escape$typescript$escape$,
