INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1757b2e5-d6e4-41df-9170-c25741ce739b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik API Layer — One HTTP Client, Server$ Interceptors, No Raw Fetch in Components$escape$,
  $escape$Qwik's resumability model serializes component state across server/client boundaries — raw fetch calls inside components break this contract and leak request context into client bundles. Centralize all HTTP calls behind server$ functions, which execute exclusively on the server and expose only serializable return values to the client.

Define a single apiFetch helper in lib/api.ts that owns base URL, default headers, and error normalization. Wrap it in server$ exports that inject auth tokens via this.cookie (Qwik City's built-in request context) and implement retry logic before returning. routeLoader$ and routeAction$ in your route files call these server$ exports — never fetch directly.

This enforces three guarantees: (1) auth tokens never reach client JS bundles, (2) retry/backoff logic lives in one file, (3) Qwik's lazy-loading $ boundaries stay clean because server$ functions are automatically excluded from client chunks. For useResource$, wrap the call in a server$ as well — track() dependencies remain reactive while the network layer stays fully server-isolated. The component never knows a network exists.$escape$,
  $escape$// lib/api.ts
import { server$ } from '@builder.io/qwik-city';

const BASE = import.meta.env.VITE_API_URL;

async function apiFetch(path: string, init?: RequestInit, retries = 2): Promise<unknown> {
  const res = await fetch(`${BASE}${path}`, { 'Content-Type': 'application/json', ...init });
  if (res.status === 429 && retries > 0) {
    await new Promise(r => setTimeout(r, 500));
    return apiFetch(path, init, retries - 1);
  }
  if (!res.ok) throw new Error(`${res.status} ${path}`);
  return res.json();
}

export const apiGet = server$(async function (path: string) {
  const token = this.cookie.get('auth')?.value;
  return apiFetch(path, { headers: { Authorization: `Bearer ${token}` } });
});$escape$,
