INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '402675cc-54bc-4828-83ee-97718e36bc0b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Animations — CSS Signals, Motion One, and prefers-reduced-motion$escape$,
  $escape$Qwik's resumability model means DOM manipulation belongs in `useVisibleTask$`, not a lifecycle hook. For simple state-driven styles, signal-driven class toggling is zero-overhead: bind a class to a signal and let CSS transitions do the work — no JS animation loop, no hydration cost.

For complex sequences — staggered lists, spring physics, keyframe choreography — reach for `@motionone/dom`. Framer Motion is React-only; Motion One is its framework-agnostic sibling and integrates cleanly with Qwik because it operates directly on DOM elements, not a virtual DOM.

The critical pattern: always gate imperative animation behind a `prefers-reduced-motion` check. Since `useVisibleTask$` is guaranteed browser-only, `window.matchMedia('(prefers-reduced-motion: reduce)').matches` is safe here — return early and rely on CSS fallbacks instead.

Use `track()` inside `useVisibleTask$` to reactively re-trigger animations when a signal changes. This replaces React's dependency array. Never put imperative DOM animation in `onClick$` handlers expecting a ref — the ref may not be resolved at call time without `useVisibleTask$` guarding it.$escape$,
  $escape$import { component$, useSignal, useVisibleTask$ } from '@builder.io/qwik';
import { animate } from '@motionone/dom';

export default component$(() => {
  const cardRef = useSignal<Element>();
  const visible = useSignal(false);

  useVisibleTask$(({ track }) => {
    track(() => visible.value);
    const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (reduced || !cardRef.value) return;
    animate(
      cardRef.value,
      { opacity: visible.value ? [0, 1] : [1, 0], y: visible.value ? [-12, 0] : [0, -12] },
      { duration: 0.25, easing: 'ease-out' }
    );
  });

  return (
    <>
      <button onClick$={() => (visible.value = !visible.value)}>Toggle</button>
      <div ref={cardRef} class={visible.value ? 'block' : 'hidden'}>Card</div>
    </>
  );
});$escape$,
  $escape$typescript$escape$,
