INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1d4ae77c-9d42-415d-b2b5-fcb1aaf03471',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Bundle Optimization — Tree-Shaking, Lazy Segments, and Bundle Analysis$escape$,
  $escape$Qwik's optimizer automatically splits your app into fine-grained lazy chunks via its `$` suffix convention — every `component$`, `useTask$`, and event handler becomes its own separate segment. But you can push further. Heavy third-party dependencies inside components are only downloaded when that component is resumed, so wrapping costly libraries in `component$` keeps them out of the initial load entirely. Use `useVisibleTask$` instead of `useTask$` for non-critical side effects — it defers execution until the element is visible, preventing unnecessary hydration work. For bundle analysis, run `npm run build` and inspect `dist/build/` — Qwik emits a `q-manifest.json` that maps every symbol to its chunk. Pair this with `vite-bundle-visualizer` by adding it to your `vite.config.ts` plugins. Avoid barrel files (`index.ts` re-exports) in shared modules — Vite's tree-shaker struggles with them and Qwik's optimizer can't split what Vite doesn't isolate. Prefer direct imports to keep each segment tight.$escape$,
  $escape$// vite.config.ts
import { defineConfig } from 'vite';
import { qwikVite } from '@builder.io/qwik/optimizer';
import { qwikCity } from '@builder.io/qwik-city/vite';
import { visualizer } from 'rollup-plugin-visualizer';

export default defineConfig(() => ({
  plugins: [
    qwikCity(),
    qwikVite(),
    visualizer({
      filename: 'dist/stats.html',
      open: true,
      gzipSize: true,
    }),
  ],
}));

// Lazy heavy component — only loads when rendered
export const HeavyChart = component$(() => {
  useVisibleTask$(async () => {
    const { Chart } = await import('chart.js'); // deferred until visible
    // init chart
  });
  return <canvas />;
});$escape$,
