INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4514bd65-14b4-4308-b248-c1700cc06620',
  '00000000-0000-0000-0000-000000000001',
  $escape$Qwik Production Monitoring — Sentry, Web Vitals, and Source Maps$escape$,
  $escape$`@sentry/qwik` hooks into Qwik City's router at the signal level — route errors and server `routeLoader$` exceptions are captured automatically without wrapping every handler. Initialize the client SDK inside `useVisibleTask$` in `src/root.tsx` so it only runs post-resumption, never during SSR. Keep `tracesSampleRate` low (0.1–0.2); Qwik's fine-grained lazy loading generates many small transactions that inflate quota fast.

For source maps, set `build: { sourcemap: true }` in `vite.config.ts` and add `@sentry/vite-plugin` — it uploads maps to Sentry after each build and strips them from the public bundle. Point `sourcemaps.assets` at `./dist/build/**`; Qwik outputs chunks there, not a flat `assets/` dir.

Web Vitals: Qwik's resumability means TTI is near-zero, but LCP and CLS still need watching. Wire `web-vitals` callbacks in the same `useVisibleTask$` block and push metrics via `Sentry.getCurrentScope().setMeasurement()`. This collapses error tracking and performance observability into one pipeline instead of shipping a separate analytics SDK.$escape$,
  $escape$// src/root.tsx
import { component$, useVisibleTask$ } from '@builder.io/qwik';
import * as Sentry from '@sentry/qwik';
import { onLCP, onCLS } from 'web-vitals';

export default component$(() => {
  useVisibleTask$(() => {
    Sentry.init({
      dsn: import.meta.env.PUBLIC_SENTRY_DSN,
      tracesSampleRate: 0.1,
      integrations: [Sentry.browserTracingIntegration()],
    });
    onLCP(m => Sentry.getCurrentScope().setMeasurement('lcp', m.value, 'millisecond'));
    onCLS(m => Sentry.getCurrentScope().setMeasurement('cls', m.value, ''));
  });
  return <></>;  // wrap around QwikCityProvider in real usage
});$escape$,
  $escape$typescript$escape$,
